```javascript
function debounce(fn, delay, options = {}) {
  const { leading = false, trailing = true } = options;
  let timer = null;
  let lastArgs = null;
  let lastThis = null;

  function invoke() {
    fn.apply(lastThis, lastArgs);
    lastArgs = null;
    lastThis = null;
  }

  function debounced(...args) {
    lastArgs = args;
    lastThis = this;

    const callNow = leading && timer === null;

    if (timer !== null) {
      clearTimeout(timer);
    }

    if (trailing || callNow) {
      timer = setTimeout(() => {
        timer = null;
        if (trailing) invoke();
      }, delay);
    }

    if (callNow) invoke();
  }

  debounced.cancel = function () {
    if (timer !== null) {
      clearTimeout(timer);
      timer = null;
    }
    lastArgs = null;
    lastThis = null;
  };

  debounced.flush = function () {
    if (timer !== null && lastArgs !== null) {
      clearTimeout(timer);
      timer = null;
      invoke();
    }
  };

  return debounced;
}
```

核心行为：

- **leading**：是否在首次调用时立即执行（默认 `false`）
- **trailing**：是否在停止触发后执行最后一次（默认 `true`）
- 两者可以同时为 `true`，实现经典的 "执行首次 + 尾随节流" 效果
- 返回的 `cancel()` 取消所有待执行调用
- 返回的 `flush()` 立即执行最后一次排队调用

典型用法：

```javascript
const handleSearch = debounce(
  (query) => fetchSearch(query),
  300
);

input.addEventListener('input', handleSearch);
// handleSearch.cancel();  // 需要时取消
```

